			assert.rejects(plugins.toggleActive(activePlugins[0]), Error).then(() => {
				plugins.isActive(activePlugins[0], (err, isActive) => {
					assert.ifError(err);
					assert(isActive);
					done();
				});
			});
		});

		it('should not activate a plugin if active plugins are set in configuration', (done) => {
