/**
 * Integration test: Plugin validation with actual NodeBB plugins module
 * This test applies the validation monkey-patch to the actual NodeBB Plugins object
 * and verifies that validation works correctly with the real plugin system
 */

const assert = require('assert');
const path = require('path');
const nconf = require('nconf');

const db = require('/app/test/mocks/databasemock');
const plugins = require('/app/src/plugins');

describe('Plugin Validation Integration with NodeBB', () => {
	let validationModule;

	before(() => {
		// Load and apply the validation module
		validationModule = require('/app/node_modules/nodebb-plugin-validation');
		validationModule(plugins);
	});

	describe('toggleActive validation', () => {
		it('should accept valid plugin identifier', async () => {
			// This would fail with the actual database, but we're just testing validation
			try {
				await plugins.toggleActive('nodebb-plugin-markdown');
				// If no error, validation passed
			} catch (err) {
				// The error should be about database/config, not validation
				assert(!err.message.includes('invalid-plugin-id'));
				assert(!err.message.includes('plugin-id-cannot-contain-whitespace'));
				assert(!err.message.includes('plugin-id-invalid-format'));
			}
		});

		it('should reject identifier with whitespace', async () => {
			try {
				await plugins.toggleActive('nodebb-plugin test');
				assert.fail('Should have thrown validation error');
			} catch (err) {
				assert(
					err.message.includes('plugin-id-cannot-contain-whitespace'),
					`Expected whitespace error, got: ${err.message}`
				);
			}
		});

		it('should reject invalid format', async () => {
			try {
				await plugins.toggleActive('invalid-plugin');
				assert.fail('Should have thrown validation error');
			} catch (err) {
				assert(
					err.message.includes('plugin-id-invalid-format'),
					`Expected invalid format error, got: ${err.message}`
				);
			}
		});

		it('should reject empty string', async () => {
			try {
				await plugins.toggleActive('');
				assert.fail('Should have thrown validation error');
			} catch (err) {
				assert(
					err.message.includes('invalid-plugin-id'),
					`Expected invalid-plugin-id error, got: ${err.message}`
				);
			}
		});

		it('should reject null', async () => {
			try {
				await plugins.toggleActive(null);
				assert.fail('Should have thrown validation error');
			} catch (err) {
				assert(
					err.message.includes('invalid-plugin-id'),
					`Expected invalid-plugin-id error, got: ${err.message}`
				);
			}
		});
	});

	describe('isActive validation', () => {
		it('should accept valid plugin identifier', async () => {
			try {
				await plugins.isActive('nodebb-plugin-markdown');
				// If no error, validation passed
			} catch (err) {
				// Should not be a validation error
				assert(!err.message.includes('invalid-plugin-id'));
				assert(!err.message.includes('plugin-id-cannot-contain-whitespace'));
				assert(!err.message.includes('plugin-id-invalid-format'));
			}
		});

		it('should reject identifier with leading whitespace', async () => {
			try {
				await plugins.isActive(' nodebb-plugin-markdown');
				assert.fail('Should have thrown validation error');
			} catch (err) {
				assert(err.message.includes('plugin-id-cannot-contain-whitespace'));
			}
		});
	});

	describe('isInstalled validation', () => {
		it('should accept valid theme identifier', async () => {
			try {
				await plugins.isInstalled('nodebb-theme-lavender');
				// Validation passed
			} catch (err) {
				assert(!err.message.includes('invalid-plugin-id'));
				assert(!err.message.includes('plugin-id-invalid-format'));
			}
		});

		it('should reject non-string', async () => {
			try {
				await plugins.isInstalled(123);
				assert.fail('Should have thrown validation error');
			} catch (err) {
				assert(err.message.includes('invalid-plugin-id'));
			}
		});
	});

	describe('checkWhitelist validation', () => {
		it('should accept valid plugin identifier before checking whitelist', async () => {
			try {
				await plugins.checkWhitelist('nodebb-plugin-markdown', 'latest');
				// Validation passed, then would check whitelist
			} catch (err) {
				// Error should be from whitelist check, not validation
				assert(
					!err.message.includes('plugin-id-cannot-contain-whitespace') &&
					!err.message.includes('invalid-plugin-id') &&
					!err.message.includes('plugin-id-invalid-format'),
					`Validation error when there should be none: ${err.message}`
				);
			}
		});

		it('should reject identifier with special characters', async () => {
			try {
				await plugins.checkWhitelist('nodebb-plugin-test@', 'latest');
				assert.fail('Should have thrown validation error');
			} catch (err) {
				assert(
					err.message.includes('plugin-id-invalid-format'),
					`Expected invalid format error, got: ${err.message}`
				);
			}
		});
	});

	describe('suggest validation', () => {
		it('should accept valid plugin identifier', async () => {
			try {
				await plugins.suggest('nodebb-plugin-markdown', '1.0.0');
				// Validation passed
			} catch (err) {
				// Error should be from suggestion logic, not validation
				assert(
					!err.message.includes('plugin-id-cannot-contain-whitespace') &&
					!err.message.includes('invalid-plugin-id') &&
					!err.message.includes('plugin-id-invalid-format'),
					`Validation error when there should be none: ${err.message}`
				);
			}
		});

		it('should reject identifier with tabs', async () => {
			try {
				await plugins.suggest('nodebb-plugin\ttest', '1.0.0');
				assert.fail('Should have thrown validation error');
			} catch (err) {
				assert(err.message.includes('plugin-id-cannot-contain-whitespace'));
			}
		});
	});

	describe('toggleInstall validation', () => {
		it('should validate plugin identifier before installing', async () => {
			try {
				await plugins.toggleInstall('nodebb-plugin-markdown', 'latest');
				// Validation passed
			} catch (err) {
				// Error should not be validation
				assert(!err.message.includes('plugin-id-invalid-format'));
				assert(!err.message.includes('invalid-plugin-id'));
			}
		});

		it('should reject identifier with newline', async () => {
			try {
				await plugins.toggleInstall('nodebb-plugin\ntest', 'latest');
				assert.fail('Should have thrown validation error');
			} catch (err) {
				assert(err.message.includes('plugin-id-cannot-contain-whitespace'));
			}
		});
	});

	describe('upgrade validation', () => {
		it('should accept scoped plugin identifier', async () => {
			try {
				await plugins.upgrade('@nodebb/nodebb-plugin-abc', 'latest');
				// Validation passed
			} catch (err) {
				assert(!err.message.includes('invalid-plugin-id'));
				assert(!err.message.includes('plugin-id-invalid-format'));
			}
		});

		it('should reject identifier without required type', async () => {
			try {
				await plugins.upgrade('nodebb-invalid-test', 'latest');
				assert.fail('Should have thrown validation error');
			} catch (err) {
				assert(err.message.includes('plugin-id-invalid-format'));
			}
		});
	});

	describe('Valid identifier patterns', () => {
		const validIds = [
			'nodebb-plugin-markdown',
			'nodebb-plugin-my-awesome-plugin',
			'nodebb-theme-lavender',
			'nodebb-widget-essentials',
			'nodebb-rewards-essentials',
			'@myorg/nodebb-plugin-test',
			'@nodebb/nodebb-plugin-abc',
			'nodebb-plugin-test-123',
		];

		validIds.forEach(id => {
			it(`should accept "${id}"`, async () => {
				try {
					await plugins.isActive(id);
					// Validation passed
				} catch (err) {
					assert(
						!err.message.includes('invalid-plugin-id') &&
						!err.message.includes('plugin-id-cannot-contain-whitespace') &&
						!err.message.includes('plugin-id-invalid-format'),
						`Validation should pass for "${id}", got: ${err.message}`
					);
				}
			});
		});
	});

	describe('Invalid identifier patterns', () => {
		const invalidIds = [
			{ id: null, reason: 'null' },
			{ id: undefined, reason: 'undefined' },
			{ id: '', reason: 'empty string' },
			{ id: 123, reason: 'non-string' },
			{ id: ' plugin', reason: 'leading space' },
			{ id: 'plugin ', reason: 'trailing space' },
			{ id: 'plugin test', reason: 'space in middle' },
			{ id: 'plugin\ttest', reason: 'tab character' },
			{ id: 'plugin\ntest', reason: 'newline' },
			{ id: 'my-plugin', reason: 'no nodebb prefix' },
			{ id: 'nodebb-invalid-test', reason: 'invalid type' },
			{ id: 'nodebb-plugin-test@', reason: 'special character' },
			{ id: '@/nodebb-plugin-test', reason: 'invalid scope' },
		];

		invalidIds.forEach(({ id, reason }) => {
			it(`should reject "${id}" (${reason})`, async () => {
				try {
					await plugins.isActive(id);
					assert.fail(`Should have rejected "${id}"`);
				} catch (err) {
					const isValidationError =
						err.message.includes('invalid-plugin-id') ||
						err.message.includes('plugin-id-cannot-contain-whitespace') ||
						err.message.includes('plugin-id-invalid-format');
					assert(isValidationError, `Expected validation error for "${id}", got: ${err.message}`);
				}
			});
		});
	});
});

