				await plugins.toggleInstall('nodebb-plugin\ntest', 'latest');
				assert.fail('Should have thrown validation error');
			} catch (err) {
				assert(err.message.includes('plugin-id-cannot-contain-whitespace'));
			}
		});
	});

	describe('upgrade validation', () => {
		it('should accept scoped plugin identifier', async () => {
			try {
				await plugins.upgrade('@nodebb/nodebb-plugin-abc', 'latest');
				// Validation passed
			} catch (err) {
				assert(!err.message.includes('invalid-plugin-id'));
				assert(!err.message.includes('plugin-id-invalid-format'));
			}
		});

		it('should reject identifier without required type', async () => {
			try {
				await plugins.upgrade('nodebb-invalid-test', 'latest');
				assert.fail('Should have thrown validation error');
			} catch (err) {
				assert(err.message.includes('plugin-id-invalid-format'));
			}
		});
	});

	describe('Valid identifier patterns', () => {
		const validIds = [
			'nodebb-plugin-markdown',
			'nodebb-plugin-my-awesome-plugin',
			'nodebb-theme-lavender',
			'nodebb-widget-essentials',
			'nodebb-rewards-essentials',
			'@myorg/nodebb-plugin-test',
			'@nodebb/nodebb-plugin-abc',
			'nodebb-plugin-test-123',
		];

		validIds.forEach(id => {
			it(`should accept "${id}"`, async () => {
				try {
					await plugins.isActive(id);
					// Validation passed
				} catch (err) {
					assert(
						!err.message.includes('invalid-plugin-id') &&
						!err.message.includes('plugin-id-cannot-contain-whitespace') &&
						!err.message.includes('plugin-id-invalid-format'),
						`Validation should pass for "${id}", got: ${err.message}`
					);
				}
			});
		});
	});

	describe('Invalid identifier patterns', () => {
		const invalidIds = [
			{ id: null, reason: 'null' },
			{ id: undefined, reason: 'undefined' },
			{ id: '', reason: 'empty string' },
			{ id: 123, reason: 'non-string' },
			{ id: ' plugin', reason: 'leading space' },
			{ id: 'plugin ', reason: 'trailing space' },
			{ id: 'plugin test', reason: 'space in middle' },
			{ id: 'plugin\ttest', reason: 'tab character' },
			{ id: 'plugin\ntest', reason: 'newline' },
			{ id: 'my-plugin', reason: 'no nodebb prefix' },
			{ id: 'nodebb-invalid-test', reason: 'invalid type' },
			{ id: 'nodebb-plugin-test@', reason: 'special character' },
			{ id: '@/nodebb-plugin-test', reason: 'invalid scope' },
		];

		invalidIds.forEach(({ id, reason }) => {
			it(`should reject "${id}" (${reason})`, async () => {
				try {
					await plugins.isActive(id);
					assert.fail(`Should have rejected "${id}"`);
				} catch (err) {
					const isValidationError =
						err.message.includes('invalid-plugin-id') ||
						err.message.includes('plugin-id-cannot-contain-whitespace') ||
						err.message.includes('plugin-id-invalid-format');
					assert(isValidationError, `Expected validation error for "${id}", got: ${err.message}`);
				}
			});
		});
	});
});

